'use client';

import React, { useEffect, useState } from 'react';
import { Table, Tag, Space, Typography, Card } from 'antd';
import { AppGrid } from '@/app/components/common/AppGrid';
import { useTranslation } from 'react-i18next';
import { useNotification } from '@/lib/NotificationProvider';

const { Title } = Typography;

export default function JobLogsPage() {
    const { t } = useTranslation();
    const [logs, setLogs] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const { connection } = useNotification();

    const fetchLogs = async () => {
        setLoading(true);
        try {
            const token = localStorage.getItem('access_token');
            const response = await fetch('/api/proxy/api/JobLogs', {
                headers: {
                    'Authorization': `Bearer ${token}`
                }
            });
            const data = await response.json();
            setLogs(data.items || []);
        } catch (error) {
            console.error('Failed to fetch logs:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchLogs();

        if (connection) {
            connection.on('ReceiveJobStatus', () => {
                // Refresh logs when a job status changes
                fetchLogs();
            });
        }
    }, [connection]);

    const columns = [
        {
            title: 'Job Name',
            dataIndex: 'jobName',
            key: 'jobName',
        },
        {
            title: 'Status',
            dataIndex: 'status',
            key: 'status',
            render: (status: string) => {
                let color = 'blue';
                if (status === 'Success') color = 'green';
                if (status === 'Failed') color = 'red';
                if (status === 'Running') color = 'orange';
                return <Tag color={color}>{status}</Tag>;
            }
        },
        {
            title: 'Message',
            dataIndex: 'message',
            key: 'message',
        },
        {
            title: 'Started At',
            dataIndex: 'startedAt',
            key: 'startedAt',
            render: (date: string) => date ? new Date(date).toLocaleString() : '-',
        },
        {
            title: 'Completed At',
            dataIndex: 'completedAt',
            key: 'completedAt',
            render: (date: string) => date ? new Date(date).toLocaleString() : '-',
        }
    ];

    return (
        <Card title={<Title level={4}>Lịch sử Jobs (Hangfire)</Title>}>
            <AppGrid
                dataSource={logs}
                columns={columns}
                rowKey="id"
                loading={loading}
                pagination={{ pageSize: 10 }}
            />
        </Card>
    );
}
